def with_retry(fn, attempts):
    def wrapper(*args, **kwargs):
        last_exc = None
        for i in range(1, attempts + 1):
            print(f'attempt {i}')
            try:
                return fn(*args, **kwargs)
            except Exception as e:
                last_exc = e
        raise last_exc
    return wrapper

call_count = [0]
def flaky():
    call_count[0] += 1
    if call_count[0] < 3:
        raise RuntimeError('not ready')
    return 'ok'

retried = with_retry(flaky, 3)
print(retried())
